1380	void diffcore_rename_extended(struct diff_options *options,
1381				      struct mem_pool *pool,
1382				      struct strintmap *relevant_sources,
1383				      struct strintmap *dirs_removed,
1384				      struct strmap *dir_rename_count,
1385				      struct strmap *cached_pairs)
1386	{
1387		int detect_rename = options->detect_rename;
1388		int minimum_score = options->rename_score;
1389		struct diff_queue_struct *q = &diff_queued_diff;
1390		struct diff_queue_struct outq = DIFF_QUEUE_INIT;
1391		struct diff_score *mx;
1392		int i, j, rename_count, skip_unmodified = 0;
1393		int num_destinations, dst_cnt;
1394		int num_sources, want_copies;
1395		struct progress *progress = NULL;
1396		struct mem_pool local_pool;
1397		struct dir_rename_info info;
1398		struct diff_populate_filespec_options dpf_options = {
1399			.check_binary = 0,
1400			.missing_object_cb = NULL,
1401			.missing_object_data = NULL
1402		};
1403		struct inexact_prefetch_options prefetch_options = {
1404			.repo = options->repo
1405		};
1406	
1407		trace2_region_enter("diff", "setup", options->repo);
1408		info.setup = 0;
1409		ASSERT(!dir_rename_count || strmap_empty(dir_rename_count));
1410		want_copies = (detect_rename == DIFF_DETECT_COPY);
1411		if (dirs_removed && (break_idx || want_copies))
1412			BUG("dirs_removed incompatible with break/copy detection");
1413		if (break_idx && relevant_sources)
1414			BUG("break detection incompatible with source specification");
1415		if (!minimum_score)
1416			minimum_score = DEFAULT_RENAME_SCORE;
1417	
1418		for (i = 0; i < q->nr; i++) {
1419			struct diff_filepair *p = q->queue[i];
1420			if (!DIFF_FILE_VALID(p->one)) {
1421				if (!DIFF_FILE_VALID(p->two))
1422					continue; /* unmerged */
1423				else if (options->single_follow &&
1424					 strcmp(options->single_follow, p->two->path))
1425					continue; /* not interested */
1426				else if (!options->flags.rename_empty &&
1427					 is_empty_blob_oid(&p->two->oid, the_repository->hash_algo))
1428					continue;
1429				else if (add_rename_dst(p) < 0) {
1430					warning("skipping rename detection, detected"
1431						" duplicate destination '%s'",
1432						p->two->path);
1433					goto cleanup;
1434				}
1435			}
1436			else if (!options->flags.rename_empty &&
1437				 is_empty_blob_oid(&p->one->oid, the_repository->hash_algo))
1438				continue;
1439			else if (!DIFF_PAIR_UNMERGED(p) && !DIFF_FILE_VALID(p->two)) {
1440				/*
1441				 * If the source is a broken "delete", and
1442				 * they did not really want to get broken,
1443				 * that means the source actually stays.
1444				 * So we increment the "rename_used" score
1445				 * by one, to indicate ourselves as a user
1446				 */
1447				if (p->broken_pair && !p->score)
1448					p->one->rename_used++;
1449				register_rename_src(p);
1450			}
1451			else if (want_copies) {
1452				/*
1453				 * Increment the "rename_used" score by
1454				 * one, to indicate ourselves as a user.
1455				 */
1456				p->one->rename_used++;
1457				register_rename_src(p);
1458			}
1459		}
1460		trace2_region_leave("diff", "setup", options->repo);
1461		if (rename_dst_nr == 0 || rename_src_nr == 0)
1462			goto cleanup; /* nothing to do */
1463	
1464		trace2_region_enter("diff", "exact renames", options->repo);
1465		mem_pool_init(&local_pool, 32*1024);
1466		/*
1467		 * We really want to cull the candidates list early
1468		 * with cheap tests in order to avoid doing deltas.
1469		 */
1470		rename_count = find_exact_renames(options, &local_pool);
1471		/*
1472		 * Discard local_pool immediately instead of at "cleanup:" in order
1473		 * to reduce maximum memory usage; inexact rename detection uses up
1474		 * a fair amount of memory, and mem_pools can too.
1475		 */
1476		mem_pool_discard(&local_pool, 0);
1477		trace2_region_leave("diff", "exact renames", options->repo);
1478	
1479		/* Did we only want exact renames? */
1480		if (minimum_score == MAX_SCORE)
1481			goto cleanup;
1482	
1483		num_sources = rename_src_nr;
1484	
1485		if (want_copies || break_idx) {
1486			/*
1487			 * Cull sources:
1488			 *   - remove ones corresponding to exact renames
1489			 *   - remove ones not found in relevant_sources
1490			 */
1491			trace2_region_enter("diff", "cull after exact", options->repo);
1492			remove_unneeded_paths_from_src(want_copies, relevant_sources);
1493			trace2_region_leave("diff", "cull after exact", options->repo);
1494		} else {
1495			/* Determine minimum score to match basenames */
1496			double factor = 0.5;
1497			char *basename_factor = getenv("GIT_BASENAME_FACTOR");
1498			int min_basename_score;
1499	
1500			if (basename_factor)
1501				factor = strtol(basename_factor, NULL, 10)/100.0;
1502			assert(factor >= 0.0 && factor <= 1.0);
1503			min_basename_score = minimum_score +
1504				(int)(factor * (MAX_SCORE - minimum_score));
1505	
1506			/*
1507			 * Cull sources:
1508			 *   - remove ones involved in renames (found via exact match)
1509			 */
1510			trace2_region_enter("diff", "cull after exact", options->repo);
1511			remove_unneeded_paths_from_src(want_copies, NULL);
1512			trace2_region_leave("diff", "cull after exact", options->repo);
1513	
1514			/* Preparation for basename-driven matching. */
1515			trace2_region_enter("diff", "dir rename setup", options->repo);
1516			initialize_dir_rename_info(&info, relevant_sources,
1517						   dirs_removed, dir_rename_count,
1518						   cached_pairs);
1519			trace2_region_leave("diff", "dir rename setup", options->repo);
1520	
1521			/* Utilize file basenames to quickly find renames. */
1522			trace2_region_enter("diff", "basename matches", options->repo);
1523			rename_count += find_basename_matches(options,
1524							      min_basename_score,
1525							      &info,
1526							      relevant_sources,
1527							      dirs_removed);
1528			trace2_region_leave("diff", "basename matches", options->repo);
1529	
1530			/*
1531			 * Cull sources, again:
1532			 *   - remove ones involved in renames (found via basenames)
1533			 *   - remove ones not found in relevant_sources
1534			 * and
1535			 *   - remove ones in relevant_sources which are needed only
1536			 *     for directory renames IF no ancestry directory
1537			 *     actually needs to know any more individual path
1538			 *     renames under them
1539			 */
1540			trace2_region_enter("diff", "cull basename", options->repo);
1541			remove_unneeded_paths_from_src(want_copies, relevant_sources);
1542			handle_early_known_dir_renames(&info, relevant_sources,
1543						       dirs_removed);
1544			trace2_region_leave("diff", "cull basename", options->repo);
1545		}
1546	
1547		/* Calculate how many rename destinations are left */
1548		num_destinations = (rename_dst_nr - rename_count);
1549		num_sources = rename_src_nr; /* rename_src_nr reflects lower number */
1550	
1551		/* All done? */
1552		if (!num_destinations || !num_sources)
1553			goto cleanup;
1554	
1555		switch (too_many_rename_candidates(num_destinations, num_sources,
1556						   options)) {
1557		case 1:
1558			goto cleanup;
1559		case 2:
1560			options->degraded_cc_to_c = 1;
1561			skip_unmodified = 1;
1562			break;
1563		default:
1564			break;
1565		}
1566	
1567		trace2_region_enter("diff", "inexact renames", options->repo);
1568		if (options->show_rename_progress) {
1569			progress = start_delayed_progress(
1570					the_repository,
1571					_("Performing inexact rename detection"),
1572					(uint64_t)num_destinations * (uint64_t)num_sources);
1573		}
1574	
1575		/* Finish setting up dpf_options */
1576		prefetch_options.skip_unmodified = skip_unmodified;
1577		if (repo_has_promisor_remote(options->repo)) {
1578			dpf_options.missing_object_cb = inexact_prefetch;
1579			dpf_options.missing_object_data = &prefetch_options;
1580		}
1581	
1582		CALLOC_ARRAY(mx, st_mult(NUM_CANDIDATE_PER_DST, num_destinations));
1583		for (dst_cnt = i = 0; i < rename_dst_nr; i++) {
1584			struct diff_filespec *two = rename_dst[i].p->two;
1585			struct diff_score *m;
1586	
1587			if (rename_dst[i].is_rename)
1588				continue; /* exact or basename match already handled */
1589	
1590			m = &mx[dst_cnt * NUM_CANDIDATE_PER_DST];
1591			for (j = 0; j < NUM_CANDIDATE_PER_DST; j++)
1592				m[j].dst = -1;
1593	
1594			for (j = 0; j < rename_src_nr; j++) {
1595				struct diff_filespec *one = rename_src[j].p->one;
1596				struct diff_score this_src;
1597	
1598				assert(!one->rename_used || want_copies || break_idx);
1599	
1600				if (skip_unmodified &&
1601				    diff_unmodified_pair(rename_src[j].p))
1602					continue;
1603	
1604				this_src.score = estimate_similarity(options->repo,
1605								     one, two,
1606								     minimum_score,
1607								     &dpf_options);
1608				this_src.name_score = basename_same(one, two);
1609				this_src.dst = i;
1610				this_src.src = j;
1611				record_if_better(m, &this_src);
1612				/*
1613				 * Once we run estimate_similarity,
1614				 * We do not need the text anymore.
1615				 */
1616				diff_free_filespec_blob(one);
1617				diff_free_filespec_blob(two);
1618			}
1619			dst_cnt++;
1620			display_progress(progress,
1621					 (uint64_t)dst_cnt * (uint64_t)num_sources);
1622		}
1623		stop_progress(&progress);
1624	
1625		/* cost matrix sorted by most to least similar pair */
1626		STABLE_QSORT(mx, dst_cnt * NUM_CANDIDATE_PER_DST, score_compare);
1627	
1628		rename_count += find_renames(mx, dst_cnt, minimum_score, 0,
1629					     &info, dirs_removed);
1630		if (want_copies)
1631			rename_count += find_renames(mx, dst_cnt, minimum_score, 1,
1632						     &info, dirs_removed);
1633		free(mx);
1634		trace2_region_leave("diff", "inexact renames", options->repo);
1635	
1636	 cleanup:
1637		/* At this point, we have found some renames and copies and they
1638		 * are recorded in rename_dst.  The original list is still in *q.
1639		 */
1640		trace2_region_enter("diff", "write back to queue", options->repo);
1641		for (i = 0; i < q->nr; i++) {
1642			struct diff_filepair *p = q->queue[i];
1643			struct diff_filepair *pair_to_free = NULL;
1644	
1645			if (DIFF_PAIR_UNMERGED(p)) {
1646				diff_q(&outq, p);
1647			}
1648			else if (!DIFF_FILE_VALID(p->one) && DIFF_FILE_VALID(p->two)) {
1649				/* Creation */
1650				diff_q(&outq, p);
1651			}
1652			else if (DIFF_FILE_VALID(p->one) && !DIFF_FILE_VALID(p->two)) {
1653				/*
1654				 * Deletion
1655				 *
1656				 * We would output this delete record if:
1657				 *
1658				 * (1) this is a broken delete and the counterpart
1659				 *     broken create remains in the output; or
1660				 * (2) this is not a broken delete, and rename_dst
1661				 *     does not have a rename/copy to move p->one->path
1662				 *     out of existence.
1663				 *
1664				 * Otherwise, the counterpart broken create
1665				 * has been turned into a rename-edit; or
1666				 * delete did not have a matching create to
1667				 * begin with.
1668				 */
1669				if (DIFF_PAIR_BROKEN(p)) {
1670					/* broken delete */
1671					struct diff_rename_dst *dst = locate_rename_dst(p);
1672					if (options->single_follow && dst &&
1673					    strcmp(dst->p->two->path, p->two->path))
1674						dst = NULL;
1675					if (dst && dst->is_rename)
1676						/* counterpart is now rename/copy */
1677						pair_to_free = p;
1678				}
1679				else {
1680					if (p->one->rename_used)
1681						/* this path remains */
1682						pair_to_free = p;
1683				}
1684	
1685				if (!pair_to_free)
1686					diff_q(&outq, p);
1687			}
1688			else if (!diff_unmodified_pair(p))
1689				/* all the usual ones need to be kept */
1690				diff_q(&outq, p);
1691			else
1692				/* no need to keep unmodified pairs */
1693				pair_to_free = p;
1694	
1695			if (pair_to_free)
1696				pool_diff_free_filepair(pool, pair_to_free);
1697		}
1698		diff_debug_queue("done copying original", &outq);
1699	
1700		free(q->queue);
1701		*q = outq;
1702		diff_debug_queue("done collapsing", q);
1703	
1704		for (i = 0; i < rename_dst_nr; i++)
1705			if (rename_dst[i].filespec_to_free)
1706				pool_free_filespec(pool, rename_dst[i].filespec_to_free);
1707	
1708		cleanup_dir_rename_info(&info, dirs_removed, dir_rename_count != NULL);
1709		FREE_AND_NULL(rename_dst);
1710		rename_dst_nr = rename_dst_alloc = 0;
1711		FREE_AND_NULL(rename_src);
1712		rename_src_nr = rename_src_alloc = 0;
1713		if (break_idx) {
1714			strintmap_clear(break_idx);
1715			FREE_AND_NULL(break_idx);
1716		}
1717		trace2_region_leave("diff", "write back to queue", options->repo);
1718		return;
1719	}
